    {
      "expectation_id": "保险犹豫期定义准确",
      "description": "回答应准确解释保险犹豫期的基本定义，即投保人在一定期间内可无条件退保的权益。",
      "acceptance_criteria": "回答中包含对犹豫期的正确描述，如'投保人可退保的期间'，且不包含错误信息。",
      "blocking_level": "blocking",
      "evidence_path": [],
      "source": "保险常识"
    },
    {
      "expectation_id": "犹豫期期限信息完整",
      "description": "回答应提供犹豫期的具体时长（如10天或15天），并说明起算时间（如签收保单后）以及可能因渠道不同而有差异。",
      "acceptance_criteria": "回答明确了期限数值，并提及起算条件和/或不同渠道的差异。如果只提供一个数字而没有上下文，视为不完整。",
      "blocking_level": "blocking",
      "evidence_path": [],
      "source": "中国保险法规及行业惯例"
    },
    {
      "expectation_id": "回答表述清晰且无矛盾",
      "description": "回答应语句通顺、逻辑清晰，无内部矛盾或歧义。",
      "acceptance_criteria": "语句无语法错误，表达意思清楚。",
      "blocking_level": "non-blocking",
      "evidence_path": [],
      "source": "通用语言规范"
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "保险犹豫期定义准确",
      "status": "fulfilled",
      "reasoning": "回答将犹豫期定义为'投保人可在...退保的期间'，核心概念正确，虽未提及'无条件'，但未包含错误信息，基本满足定义准确性。",
      "evidence": []
    },
    {
      "expectation_id": "犹豫期期限信息完整",
      "status": "not_fulfilled",
      "reasoning": "回答仅说明'15天内'，未解释该期限的起算时间（如收到保单后），也未说明犹豫期长度可能因险种或渠道不同（如银行保险为15天，通常为10天），导致期限信息不完整且可能误导。",
      "evidence": []
    },
    {
      "expectation_id": "回答表述清晰且无矛盾",
      "status": "fulfilled",
      "reasoning": "语句简短通顺，无语法错误或矛盾。",
      "evidence": []
    }
  ],
  "overall_fulfillment": {
    "status": "not_fulfilled",
    "reason": "虽然定义了犹豫期，但关于犹豫期期限的信息不完整，缺少起算条件和不同情况下的时长差异，存在阻塞性缺失。"
  },
  "expected": {
    "actual_answer": "犹豫期，又称冷静期，指投保人在签收保单后的10天（银行保险渠道为15天）内，可以无条件解除保险合同，保险公司全额退还保费。"
  },
  "intent_model": {
    "question_intent": "用户希望了解保险专业术语'犹豫期'的含义、期限及具体规则。",
    "expected_answer_type": "简短的保险知识解释，包含定义和关键期限信息。",
    "domain": "保险"
  },
  "consumer_contract": {
    "expected_accuracy": "高",
    "expected_completeness": "中高"
  },
  "reconstructed_intent": "根据问题'什么是保险犹豫期？'，用户意图是获得该术语的准确解释，特别是它的时长和适用条件。",
  "judge_basis": "依据中国保险行业现行法规和惯例（如《保险法》及银保监会相关通知），并结合通用知识对回答的完整性、准确性进行评判。由于本案例未提供参考标准答案，评判基于judge自建的预期回答。",
